### 4. **C# - Đa luồng (Multithreading)**

```csharp
using System;
using System.Threading;

namespace MultithreadingExample
{
    class Program
    {
        static void Main(string[] args)
        {
            // Tạo và khởi động các luồng
            Thread thread1 = new Thread(WorkerMethod);
            thread1.Name = "Thread 1";
            thread1.Start();

            Thread thread2 = new Thread(WorkerMethod);
            thread2.Name = "Thread 2";
            thread2.Start();

            // Chờ các luồng hoàn thành
            thread1.Join();
            thread2.Join();

            Console.WriteLine("Tất cả các luồng đã hoàn thành.");
        }

        static void WorkerMethod()
        {
            for (int i = 0; i < 5; i++)
            {
                Console.WriteLine($"{Thread.CurrentThread.Name} đang chạy: {i}");
                Thread.Sleep(500); // Mô phỏng công việc
            }
            Console.WriteLine($"{Thread.CurrentThread.Name} đã hoàn thành.");
        }
    }
}
```

### 5. **C# - Xử lý ngoại lệ (Exception Handling)**

```csharp
using System;

namespace ExceptionHandlingExample
{
    class Program
    {
        static void Main(string[] args)
        {
            try
            {
                int[] numbers = { 1, 2, 3 };
                Console.WriteLine(numbers[5]); // Index out of range
            }
            catch (IndexOutOfRangeException ex)
            {
                Console.WriteLine($"Lỗi: Chỉ mục ngoài phạm vi - {ex.Message}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Lỗi chung: {ex.Message}");
            }
            finally
            {
                Console.WriteLine("Khối finally luôn được thực thi.");
            }
        }
    }
}
