### 6. **C# - Delegate và Event**

```csharp
using System;

namespace DelegateEventExample
{
    // Định nghĩa delegate
    public delegate void Notify(string message);

    class Processer
    {
        public event Notify ProcessCompleted;

        public void Run()
        {
            Console.WriteLine("Đang xử lý...");
            // Thực hiện công việc...
            OnProcessCompleted("Hoàn thành xử lý!");
        }

        protected virtual void OnProcessCompleted(string message)
        {
            ProcessCompleted?.Invoke(message);
        }
    }

    class Program
    {
        static void Main(string[] args)
        {
            Processer processer = new Processer();
            processer.ProcessCompleted += HandleProcessCompleted;
            processer.Run();
        }

        static void HandleProcessCompleted(string message)
        {
            Console.WriteLine($"Nhận thông báo: {message}");
        }
    }
}
```

